const useCounterObserver = (root: React.RefObject<HTMLElement | null>) => {
	useEffect(() => {
		if (typeof window === "undefined") return;
		if (!("IntersectionObserver" in window)) return;
		const rootEl = root.current;
		if (!rootEl) return;

		const counters = Array.from(
			rootEl.querySelectorAll<HTMLElement>(".counter")
		);

		const observer = new IntersectionObserver(
			(entries) => {
				for (const entry of entries) {
					if (!entry.isIntersecting) continue;
					const el = entry.target as HTMLElement;
					// Extract numeric portion safely (ignores any suffix in sibling like "+", "M+", etc.)
					const target = parseInt(
						el.innerText.replace(/\D/g, ""),
						10
					);
					if (!Number.isFinite(target)) {
						observer.unobserve(el);
						continue;
					}

					let current = 0;
					const step = target / 200; // ~2s total with 10ms tick
					const intervalId = window.setInterval(() => {
						current += step;
						const value = Math.min(Math.floor(current), target);
						el.innerText = String(value);
						if (value >= target) {
							window.clearInterval(intervalId);
						}
					}, 10);

					observer.unobserve(el);
				}
			},
			{ threshold: 0.2, rootMargin: "0px 0px -10% 0px" }
		);

		counters.forEach((el) => observer.observe(el));
		return () => observer.disconnect();
	}, [root]);
};

